nodes.notes:
Paperless-ngx — document management system. Search, view, and organize scanned documents, receipts, invoices, and mail.

Actions:
  search — full-text search across all documents. Use for "find my tax return", "search for invoice from Bell".
  get — list documents, optionally filtered by time. Use for "recent documents", "what came in this week".
  update — change document metadata including title, tags, correspondent, type, and date.
  tags — list all available tags.
  correspondents — list all available correspondents.
  types — list all available document types.

Rules:
- document_id comes from a prior search or get call. Do not fabricate document IDs.
- tags, correspondents, and types are lookup actions — use them to see what metadata values are available before updating.

---schema
{
  "action": {
    "type": "string",
    "description": "One of: search, get, update, tags, correspondents, types",
    "required": true
  },
  "query": {
    "type": "string",
    "description": "Search query text. For: search"
  },
  "document_id": {
    "type": "integer",
    "description": "Document ID. For: get, update"
  },
  "limit": {
    "type": "integer",
    "description": "Max results. Default 10. For: search, get"
  },
  "filter": {
    "type": "string",
    "description": "Filter by time period. One of: today, week, month. For: get"
  },
  "ordering": {
    "type": "string",
    "description": "Sort order. One of: created, -created. For: search"
  },
  "title": {
    "type": "string",
    "description": "New document title. For: update"
  },
  "tags": {
    "type": "string",
    "description": "Comma-separated tag names. For: update"
  },
  "correspondent": {
    "type": "string",
    "description": "Correspondent name. For: update"
  },
  "document_type": {
    "type": "string",
    "description": "Document type name. For: update"
  },
  "date": {
    "type": "string",
    "description": "Document date YYYY-MM-DD. For: update"
  }
}

parameters.jsCode:
const body = $input.item.json.body || $input.item.json;
let data = typeof body === 'string' ? JSON.parse(body) : body;

const action = (data.action || 'search').toLowerCase().trim();

// Common parameters
const limit = parseInt(data.limit) || 10;
const ordering = data.ordering || '-created';

// Search parameters
const query = data.query || '';

// Get parameters
const documentId = data.document_id || data.id || null;
const filter = (data.filter || '').toLowerCase().trim();

// Update parameters
const title = data.title || null;
const tags = data.tags || null;
const correspondent = data.correspondent || null;
const documentType = data.document_type || data.type || null;
const date = data.date || null;
const asn = data.archive_serial_number || data.asn || null;

// Tags/Correspondents/Types parameters
const actionType = (data.action_type || 'list').toLowerCase().trim();
const tagName = data.tag_name || null;
const tagId = data.tag_id || null;
const correspondentName = data.correspondent_name || null;
const correspondentId = data.correspondent_id || null;
const typeName = data.type_name || null;
const typeId = data.type_id || null;

// Build date filter for 'get' action
let dateFilter = null;
if (action === 'get' && filter) {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  if (filter === 'today') {
    dateFilter = today.toISOString().split('T')[0];
  } else if (filter === 'week') {
    const weekAgo = new Date(today);
    weekAgo.setDate(weekAgo.getDate() - 7);
    dateFilter = weekAgo.toISOString().split('T')[0];
  } else if (filter === 'month') {
    const monthAgo = new Date(today);
    monthAgo.setMonth(monthAgo.getMonth() - 1);
    dateFilter = monthAgo.toISOString().split('T')[0];
  }
}

return [{
  json: {
    action,
    query,
    limit,
    ordering,
    documentId,
    filter,
    dateFilter,
    title,
    tags,
    correspondent,
    documentType,
    date,
    asn,
    actionType,
    tagName,
    tagId,
    correspondentName,
    correspondentId,
    typeName,
    typeId
  }
}];

