parameters.jsCode:
const response = $input.item.json;
const results = response.results || [];

if (results.length === 0) {
  return [{
    json: {
      message: "No documents found matching your search.",
      documents: []
    }
  }];
}

const docs = results.slice(0, 5).map(doc => ({
  id: doc.id,
  title: doc.title,
  created: doc.created,
  correspondent: doc.correspondent_name || 'None',
  tags: doc.tags || []
}));

const message = results.length === 1 
  ? `Found 1 document: ${results[0].title}`
  : `Found ${results.length} documents. Top results: ${docs.map(d => d.title).join(', ')}`;

return [{
  json: {
    message,
    documents: docs,
    total: results.length
  }
}];

const response = $input.item.json;

// Single document response
if (response.id) {
  const doc = response;
  const message = `Document ${doc.id}: ${doc.title}. Created ${new Date(doc.created).toLocaleDateString()}. ${doc.correspondent ? 'From ' + doc.correspondent : 'No correspondent'}. ${doc.tags && doc.tags.length > 0 ? 'Tags: ' + doc.tags.join(', ') : 'No tags'}.`;

  return [{
    json: {
      message,
      document: {
        id: doc.id,
        title: doc.title,
        created: doc.created,
        correspondent: doc.correspondent || null,
        tags: doc.tags || [],
        content: doc.content || null
      }
    }
  }];
}

// Multiple documents response
const results = response.results || [];

if (results.length === 0) {
  return [{
    json: {
      message: "No recent documents found.",
      documents: []
    }
  }];
}

const docs = results.slice(0, 5).map(doc => ({
  id: doc.id,
  title: doc.title,
  created: doc.created,
  correspondent: doc.correspondent_name || 'None'
}));

const message = results.length === 1
  ? `Found 1 document: ${results[0].title}`
  : `Found ${results.length} recent documents. Latest: ${docs.map(d => d.title).join(', ')}`;

return [{
  json: {
    message,
    documents: docs,
    total: results.length
  }
}];

const doc = $input.item.json;
const message = `Updated document ${doc.id}: ${doc.title}. ${doc.correspondent ? 'Correspondent: ' + doc.correspondent : ''}${doc.tags && doc.tags.length > 0 ? ' Tags: ' + doc.tags.join(', ') : ''}`;

return [{
  json: {
    message,
    document: {
      id: doc.id,
      title: doc.title,
      correspondent: doc.correspondent || null,
      tags: doc.tags || [],
      updated: new Date().toISOString()
    }
  }
}];

const response = $input.item.json;
const params = $('Parse Parameters').item.json;

// List tags response
if (params.actionType === 'list') {
  const tags = response.results || [];

  if (tags.length === 0) {
    return [{
      json: {
        message: "No tags found.",
        tags: []
      }
    }];
  }

  const tagList = tags.slice(0, 10).map(t => t.name).join(', ');
  const message = tags.length === 1
    ? `Found 1 tag: ${tags[0].name}`
    : `Found ${tags.length} tags: ${tagList}${tags.length > 10 ? ', and more' : ''}`;

  return [{
    json: {
      message,
      tags: tags.map(t => ({ id: t.id, name: t.name, count: t.document_count || 0 }))
    }
  }];
}

// Documents by tag response
const docs = response.results || [];

if (docs.length === 0) {
  return [{
    json: {
      message: "No documents found with that tag.",
      documents: []
    }
  }];
}

const docList = docs.slice(0, 5).map(d => d.title).join(', ');
const message = docs.length === 1
  ? `Found 1 document with that tag: ${docs[0].title}`
  : `Found ${docs.length} documents with that tag. Top results: ${docList}`;

return [{
  json: {
    message,
    documents: docs.slice(0, 5).map(d => ({ id: d.id, title: d.title, created: d.created }))
  }
}];

const response = $input.item.json;
const params = $('Parse Parameters').item.json;

// List correspondents response
if (params.actionType === 'list') {
  const correspondents = response.results || [];

  if (correspondents.length === 0) {
    return [{
      json: {
        message: "No correspondents found.",
        correspondents: []
      }
    }];
  }

  const corrList = correspondents.slice(0, 10).map(c => c.name).join(', ');
  const message = correspondents.length === 1
    ? `Found 1 correspondent: ${correspondents[0].name}`
    : `Found ${correspondents.length} correspondents: ${corrList}${correspondents.length > 10 ? ', and more' : ''}`;

  return [{
    json: {
      message,
      correspondents: correspondents.map(c => ({ id: c.id, name: c.name, count: c.document_count || 0 }))
    }
  }];
}

// Documents by correspondent response
const docs = response.results || [];

if (docs.length === 0) {
  return [{
    json: {
      message: "No documents found from that correspondent.",
      documents: []
    }
  }];
}

const docList = docs.slice(0, 5).map(d => d.title).join(', ');
const message = docs.length === 1
  ? `Found 1 document from that correspondent: ${docs[0].title}`
  : `Found ${docs.length} documents from that correspondent. Top results: ${docList}`;

return [{
  json: {
    message,
    documents: docs.slice(0, 5).map(d => ({ id: d.id, title: d.title, created: d.created }))
  }
}];

const response = $input.item.json;
const params = $('Parse Parameters').item.json;

// List document types response
if (params.actionType === 'list') {
  const types = response.results || [];

  if (types.length === 0) {
    return [{
      json: {
        message: "No document types found.",
        types: []
      }
    }];
  }

  const typeList = types.slice(0, 10).map(t => t.name).join(', ');
  const message = types.length === 1
    ? `Found 1 document type: ${types[0].name}`
    : `Found ${types.length} document types: ${typeList}${types.length > 10 ? ', and more' : ''}`;

  return [{
    json: {
      message,
      types: types.map(t => ({ id: t.id, name: t.name, count: t.document_count || 0 }))
    }
  }];
}

// Documents by type response
const docs = response.results || [];

if (docs.length === 0) {
  return [{
    json: {
      message: "No documents found of that type.",
      documents: []
    }
  }];
}

const docList = docs.slice(0, 5).map(d => d.title).join(', ');
const message = docs.length === 1
  ? `Found 1 document of that type: ${docs[0].title}`
  : `Found ${docs.length} documents of that type. Top results: ${docList}`;

return [{
  json: {
    message,
    documents: docs.slice(0, 5).map(d => ({ id: d.id, title: d.title, created: d.created }))
  }
}];

const errorData = $input.item.json;
let errorMsg = errorData.message || errorData.error || 'Unknown error';

if (errorMsg.includes('401') || errorMsg.includes('Unauthorized')) {
  errorMsg = 'Authentication failed. Check the Paperless API key in n8n.';
} else if (errorMsg.includes('ECONNREFUSED') || errorMsg.includes('ETIMEDOUT')) {
  errorMsg = 'Cannot connect to Paperless. Is it running?';
} else if (errorMsg.includes('Credential')) {
  errorMsg = 'Credentials not found in n8n.';
} else if (errorMsg.includes('404')) {
  errorMsg = 'Document not found.';
}

return [{ json: { message: `Sorry, there was an error. ${errorMsg}`, error: true } }];
